mapper.select:
SELECT id, trace_id, session_id, user_id, status, event_count, duration_ms, error_message, trace_json, expected_intent, expected_slots, expected_clarify_action, labeled_by, labeled_at, label_note, created_at, updated_at FROM diet_request_trace WHERE user_id = #{userId} AND created_at >= #{startAt} AND created_at < #{endAt}
AND expected_intent IS NULL AND expected_slots IS NULL AND expected_clarify_action IS NULL
ORDER BY created_at DESC, id DESC LIMIT #{limit}
